use notify::{Config, Event, EventKind, RecommendedWatcher, RecursiveMode, Watcher};
use std::path::Path;
use std::sync::mpsc;
use tokio::sync::mpsc as tokio_mpsc;

/// Creates a non-blocking file watcher that yields events via a tokio channel.
/// Internally uses a std::sync::mpsc to collect from the synchronous watcher
/// callback, then relays events into a tokio channel from an async task.
fn async_watcher<P: AsRef<Path>>(
    path: P,
) -> notify::Result<(RecommendedWatcher, tokio_mpsc::Receiver<notify::Result<Event>>)> {
    let (sync_tx, sync_rx) = mpsc::channel();
    let (async_tx, async_rx) = tokio_mpsc::channel(100);

    let mut watcher = RecommendedWatcher::new(
        move |res| {
            let _ = sync_tx.send(res);
        },
        Config::default(),
    )?;

    watcher.watch(path.as_ref(), RecursiveMode::Recursive)?;

    // Spawn a task that relays from the sync receiver to the async channel.
    // The sync receiver is `RecvError` safe to poll in a blocking task.
    tokio::spawn(async move {
        loop {
            // We need to use `tokio::task::spawn_blocking` to wait on the
            // std::sync::mpsc::Receiver without blocking the tokio runtime.
            let res = tokio::task::spawn_blocking(move || sync_rx.recv()).await;
            match res {
                Ok(Ok(event)) => {
                    if async_tx.send(event).await.is_err() {
                        break; // receiver dropped
                    }
                }
                Ok(Err(_)) => break, // channel closed
                Err(_) => break,     // join error
            }
        }
    });

    Ok((watcher, async_rx))
}

#[tokio::main]
async fn main() -> notify::Result<()> {
    let path = std::env::args()
        .nth(1)
        .unwrap_or_else(|| ".".into());

    let (_watcher, mut rx) = async_watcher(&path)?;

    println!("Watching {:?} for changes... (Ctrl+C to stop)", path);

    while let Some(res) = rx.recv().await {
        match res {
            Ok(event) if matches!(event.kind, EventKind::Any | EventKind::Other) => continue,
            Ok(event) => {
                for path in &event.paths {
                    println!("  {:?} -> {:?}", event.kind, path.display());
                }
                // If a file was removed or created, print a summary line.
                if matches!(
                    event.kind,
                    EventKind::Create(_) | EventKind::Remove(_) | EventKind::Modify(_)
                ) {
                    println!("  [{} file(s) affected]", event.paths.len());
                }
            }
            Err(e) => eprintln!("watch error: {}", e),
        }
    }

    println!("Watcher stopped.");
    Ok(())
}
