    #[serde(rename = "type")]
    msg_type: String,
    from: String,
    text: String,
}

pub struct Server {
    rooms: Arc<RwLock<HashMap<String, Arc<RwLock<Room>>>>>,
}

impl Server {
    pub fn new() -> Self {
        Self {
            rooms: Arc::new(RwLock::new(HashMap::new())),
        }
    }

    pub async fn run(&self, addr: &str) -> Result<(), Box<dyn std::error::Error>> {
        let listener = TcpListener::bind(addr).await?;
        tracing::info!("Listening on {}", addr);

        loop {
            let (stream, _addr) = listener.accept().await?;
            let rooms = self.rooms.clone();
            tokio::spawn(async move {
                let ws_stream = match accept_async(stream).await {
                    Ok(ws) => ws,
                    Err(e) => {
                        tracing::error!("WebSocket handshake failed: {}", e);
                        return;
                    }
                };
                let (mut ws_sender, mut ws_receiver) = ws_stream.split();
                // Wait for join message
                let first_msg = match ws_receiver.next().await {
                    Some(Ok(Message::Text(text))) => text,
                    _ => return,
                };

                let chat_msg: ChatMessage = match serde_json::from_str(&first_msg) {
                    Ok(msg) => msg,
                    Err(e) => {
                        tracing::warn!("Invalid first message: {}", e);
                        return;
                    }
                };

                let (username, room_name) = match chat_msg {
                    ChatMessage::Join { username, room } => (username, room),
                    _ => return,
                };

                let client_id = Uuid::new_v4().to_string();
                let (client, mut handle) = ClientHandle::create(
                    client_id.clone(),
                    username.clone(),
                    room_name.clone(),
                );

                // Get or create room
                let room = {
                    let mut rooms_guard = rooms.write().await;
                    rooms_guard
                        .entry(room_name.clone())
                        .or_insert_with(|| Arc::new(RwLock::new(Room::new(room_name.clone()))))
                        .clone()
                };

                {
                    let mut room_guard = room.write().await;
                    room_guard.add_client(client.clone()).await;
                }

                let join_msg = OutMessage {
                    msg_type: "system".to_string(),
                    from: "server".to_string(),
                    text: format!("{} joined the room", username),
                };
                let join_json = serde_json::to_string(&join_msg).unwrap();
                room.read().await.broadcast(&join_json, &client_id).await;

                // Main loop
                loop {
                    tokio::select! {
                        msg_from_client = ws_receiver.next() => {
                            match msg_from_client {
                                Some(Ok(Message::Text(text))) => {
                                    let parsed: ChatMessage = match serde_json::from_str(&text) {
                                        Ok(m) => m,
                                        Err(_) => continue,
                                    };
                                    match parsed {
                                        ChatMessage::Chat { text } => {
                                            let out = OutMessage {
                                                msg_type: "chat".to_string(),
                                                from: username.clone(),
                                                text,
                                            };
                                            let out_json = serde_json::to_string(&out).unwrap();
                                            room.read().await.broadcast(&out_json, &client_id).await;
                                        }
                                        ChatMessage::Leave { .. } => break,
                                        _ => {}
                                    }
                                }
                                Some(Ok(Message::Close(_))) | None => break,
                                _ => {}
                            }
                        }
                        msg_to_client = handle.rx.recv() => {
                            match msg_to_client {
                                Some(text) => {
                                    if ws_sender.send(Message::Text(text)).await.is_err() {
                                        break;
                                    }
                                }
                                None => break,
                            }
                        }
                    }
                }

                // Cleanup
                {
                    let mut room_guard = room.write().await;
                    room_guard.remove_client(&client_id).await;
                }
                let leave_msg = OutMessage {
                    msg_type: "system".to_string(),
                    from: "server".to_string(),
                    text: format!("{} left the room", username),
                };
                let leave_json = serde_json::to_string(&leave_msg).unwrap();
                room.read().await.broadcast(&leave_json, &client_id).await;
            });
        }
    }
}
