+use std::time::{Duration, Instant};
+
+/// Token bucket rate limiter.
+///
+/// The bucket starts full of tokens. Tokens are consumed by requests
+/// and replenished over time at a constant rate.
+#[derive(Debug, Clone)]
+pub struct TokenBucket {
+    /// Maximum number of tokens the bucket can hold.
+    capacity: u64,
+    /// Number of tokens added per second.
+    refill_rate: u64,
+    /// Current number of available tokens.
+    tokens: f64,
+    /// Last time tokens were refilled.
+    last_refill: Instant,
+}
+
+impl TokenBucket {
+    /// Create a new token bucket.
+    ///
+    /// # Arguments
+    /// * `capacity` - Maximum tokens the bucket can hold
+    /// * `refill_rate` - Tokens added per second
+    pub fn new(capacity: u64, refill_rate: u64) -> Self {
+        let now = Instant::now();
+        Self {
+            capacity,
+            refill_rate,
+            tokens: capacity as f64,
+            last_refill: now,
+        }
+    }
+
+    /// Refill tokens based on elapsed time.
+    fn refill(&mut self) {
+        let now = Instant::now();
+        let elapsed = now.duration_since(self.last_refill);
+        let elapsed_secs = elapsed.as_secs_f64();
+        let tokens_to_add = elapsed_secs * self.refill_rate as f64;
+        self.tokens = (self.tokens + tokens_to_add).min(self.capacity as f64);
+        self.last_refill = now;
+    }
+
+    /// Try to consume `n` tokens from the bucket.
+    ///
+    /// Returns `true` if tokens were available and consumed,
+    /// `false` if the request should be rejected.
+    pub fn try_consume(&mut self, n: u64) -> bool {
+        self.refill();
+        if self.tokens >= n as f64 {
+            self.tokens -= n as f64;
+            true
+        } else {
+            false
+        }
+    }
+
+    /// Get the current number of available tokens.
+    pub fn available_tokens(&mut self) -> u64 {
+        self.refill();
+        self.tokens as u64
+    }
+
+    /// Get the time until `n` tokens become available.
+    pub fn wait_time(&mut self, n: u64) -> Duration {
+        self.refill();
+        if self.tokens >= n as f64 {
+            Duration::ZERO
+        } else {
+            let deficit = n as f64 - self.tokens;
+            let secs = deficit / self.refill_rate as f64;
+            Duration::from_secs_f64(secs)
+        }
+    }
+}
+
+#[cfg(test)]
+mod tests {
+    use super::*;
+
+    #[test]
+    fn test_basic_consume() {
+        let mut bucket = TokenBucket::new(10, 5);
+        assert!(bucket.try_consume(5));
+        assert_eq!(bucket.available_tokens(), 5);
+    }
+}
