use crate::actor::{Actor, ActorContext, ActorRef, ActorError};
use std::collections::HashMap;
use std::sync::Arc;
use tokio::sync::RwLock;
use tokio::task::JoinHandle;

type Mailbox<M> = tokio::sync::mpsc::Sender<M>;

/// The actor system manages actor lifecycles and message routing.
#[derive(Clone)]
pub struct ActorSystem {
    inner: Arc<ActorSystemInner>,
}

struct ActorSystemInner {
    name: String,
    // We store type-erased actor handles so we can manage heterogeneous actors.
    actors: RwLock<HashMap<String, ErasedActor>>,
    next_id: Arc<std::sync::atomic::AtomicU64>,
}

/// Type-erased handle to a running actor task.
struct ErasedActor {
    handle: JoinHandle<()>,
    /// We keep a dummy sender so we can detect if the actor is still alive.
    /// In a real system we'd have a proper typed registry.
    alive: Arc<std::sync::atomic::AtomicBool>,
}

impl ActorSystem {
    pub fn new(name: &str) -> Self {
        Self {
            inner: Arc::new(ActorSystemInner {
                name: name.to_string(),
                actors: RwLock::new(HashMap::new()),
                next_id: Arc::new(std::sync::atomic::AtomicU64::new(1)),
            }),
        }
    }

    pub fn name(&self) -> &str {
        &self.inner.name
    }

    fn allocate_path(&self, name: &str) -> String {
        let id = self.inner.next_id.fetch_add(1, std::sync::atomic::Ordering::Relaxed);
        format!("/{}/actor-{}-{}", self.inner.name, name, id)
    }

    /// Spawn a new actor. Returns an ActorRef that can be used to send messages.
    pub async fn spawn<A: Actor>(&self, name: &str, mut actor: A, mailbox_size: usize) -> Result<ActorRef<A::Msg>, ActorError> {
        let path = self.allocate_path(name);
        let (tx, mut rx) = tokio::sync::mpsc::channel::<A::Msg>(mailbox_size);
        let actor_ref = ActorRef::new(tx, path.clone());

        let alive = Arc::new(std::sync::atomic::AtomicBool::new(true));
        let alive_clone = alive.clone();
        let system_clone = self.clone();
        let actor_ref_clone = actor_ref.clone();

        // Pre-start hook
        let mut ctx = ActorContext {
            myself: actor_ref_clone.clone(),
            system: system_clone.clone(),
        };
        actor.pre_start(&mut ctx).await;

        let handle = tokio::spawn(async move {
            while let Some(msg) = rx.recv().await {
                actor.receive(msg, &mut ctx).await;
            }
            // Mailbox closed — post_stop
            actor.post_stop(&mut ctx).await;
            alive_clone.store(false, std::sync::atomic::Ordering::Relaxed);
        });

        let erased = ErasedActor { handle, alive };
        self.inner.actors.write().await.insert(path, erased);

        Ok(actor_ref)
    }

    /// Gracefully stop an actor by dropping its mailbox sender.
    pub async fn stop(&self, path: &str) -> Result<(), ActorError> {
        let mut actors = self.inner.actors.write().await;
        if let Some(erased) = actors.remove(path) {
            // Aborting is aggressive but ensures cleanup.
            // In a real system, we'd send a poison pill and wait.
            erased.handle.abort();
            Ok(())
        } else {
            Err(ActorError::NotFound)
        }
    }

    /// Shut down the entire system.
    pub async fn shutdown(&self) {
        let mut actors = self.inner.actors.write().await;
        for (_, erased) in actors.drain() {
            erased.handle.abort();
        }
    }

    pub async fn actor_count(&self) -> usize {
        self.inner.actors.read().await.len()
    }
}
